        assert_eq!(snapshot.refresh.phase, OverviewRefreshPhase::Ready);
        assert_eq!(snapshot.top.version, Fallout4InstallType::NextGen);
        assert_eq!(snapshot.binaries.rows[1].severity, StatusSeverity::Neutral);
        assert_eq!(
