        let archives = Vec::new();
        let modules = Vec::new();
        let enablement = enabled_files();
        let update = OverviewUpdateCheckState::Completed {
            releases: vec![UpdateRelease::new(UpdateProvider::Github, "0.7.1")],
        };

        let snapshot = OverviewDiagnostics::build(input(
            &discovery,
            &settings,
            &binaries,
